			return []byte("Ask anything"), nil
		},
	}
	inst.tmuxSession = tmux.NewTmuxSessionWithDeps("test-branch", "opencode", false, &testPtyFactory{}, cmdExec)

	err = inst.StartOnBranch("feature/task-5")
