		overlay.ContextMenuItem{Label: "mark done", Action: "mark_plan_done"},
		overlay.ContextMenuItem{Label: "start over", Action: "start_over_plan"},
		overlay.ContextMenuItem{Label: "cancel plan", Action: "cancel_plan"},
